// Normalize and validate the incoming lead data
const body = items[0].json.body || items[0].json;

const lead = {
  firstName: (body.name || body.full_name || '').split(' ')[0] || 'Unknown',
  lastName: (body.name || body.full_name || '').split(' ').slice(1).join(' ') || '',
  email: (body.email || body.email_address || '').toLowerCase().trim(),
  phone: body.phone || body.phone_number || '',
  company: body.company || body.company_name || body.organization || '',
  source: body.source || body.utm_source || 'website',
  message: body.message || body.comments || body.notes || '',
  capturedAt: new Date().toISOString(),
  rawPayload: JSON.stringify(body)
};

// Basic email validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
lead.isValidEmail = emailRegex.test(lead.email);

// Detect lead quality signals
lead.hasPhone = lead.phone.length > 0;
lead.hasCompany = lead.company.length > 0;
lead.hasMessage = lead.message.length > 0;
lead.qualityScore = (lead.isValidEmail ? 1 : 0) + (lead.hasPhone ? 1 : 0) + (lead.hasCompany ? 1 : 0) + (lead.hasMessage ? 1 : 0);

// Assign priority based on quality score
if (lead.qualityScore >= 3) {
  lead.priority = 'high';
} else if (lead.qualityScore >= 2) {
  lead.priority = 'medium';
} else {
  lead.priority = 'low';
}

return [{ json: lead }];

// Log the invalid lead for review
const lead = items[0].json;
console.log(`Invalid lead rejected: ${JSON.stringify(lead.rawPayload)}`);

return [{
  json: {
    status: 'rejected',
    reason: 'invalid_email',
    email: lead.email,
    capturedAt: lead.capturedAt,
    rawPayload: lead.rawPayload
  }
}];

const lead = items[0].json;

// Merge enrichment data if available
let enrichedLead = { ...lead };

try {
  const enrichment = items[0].json;
  if (enrichment && enrichment.data) {
    enrichedLead.emailStatus = enrichment.data.status || 'unknown';
    enrichedLead.emailScore = enrichment.data.score || 0;
    enrichedLead.companyEnriched = enrichment.data.company || lead.company;
    enrichedLead.enrichmentSource = 'hunter.io';
  }
} catch (e) {
  enrichedLead.emailStatus = 'not_verified';
  enrichedLead.enrichmentSource = 'skipped';
}

return [{ json: enrichedLead }];

